import { createTheme } from '../utils/create-theme';

// Create default global light theme
const dest = createTheme(() => ({
  mode: 'light'
}));
const Provider = dest.Provider;
const Consumer = dest.Consumer;
const useTheme = dest.useTheme;
export { useTheme as useGlobalTheme };
const Theme = {
  Provider,
  Consumer
};
// eslint-disable-next-line @repo/internal/react/require-jsdoc
export default Theme;